function formatDate(date: string | null) {
  if (!date) return "—";
  return new Date(date).toLocaleString();
}

function formatDateTime(date: Date | undefined) {
  if (!date) return "";
  return format(date, "yyyy-MM-dd HH:mm:ss");
}

